// Validate incoming payload
const body = $input.first().json.body || $input.first().json;

// ── Shell-metacharacter sanitiser (F-1 fix) ──────────────────────────────────
// Reject any value containing characters that have special meaning in a shell.
// Allowed: alphanumerics, path separators, dots, dashes, underscores.
function sanitizeArg(val, fieldName) {
  if (typeof val !== 'string') return val;
  if (/[^a-zA-Z0-9_.\/\-]/.test(val)) {
    throw new Error(
      `Input '${fieldName}' contains disallowed shell characters: ${val}. ` +
      'Only alphanumerics, path separators (/), dots, dashes and underscores are allowed.'
    );
  }
  return val;
}

// ── Path-prefix restriction (F-2 fix) ────────────────────────────────────────
const ALLOWED_PREFIX = '/app/clara_pipeline/data/';
function restrictPath(val, fieldName) {
  if (!val.startsWith(ALLOWED_PREFIX)) {
    throw new Error(
      `'${fieldName}' must be within ${ALLOWED_PREFIX}. Got: ${val}`
    );
  }
  return val;
}

const rawTranscriptPath = body.transcript_path;
const stage = body.stage || 'demo_call';
const rawModel = body.model || process.env.OLLAMA_MODEL || 'mistral';
const rawOllamaUrl = body.ollama_url || process.env.OLLAMA_URL || 'http://host.docker.internal:11434';

if (!rawTranscriptPath) {
  throw new Error('Missing required field: transcript_path');
}

if (!['demo_call', 'onboarding_call', 'onboarding_form'].includes(stage)) {
  throw new Error(`Invalid stage: ${stage}. Must be demo_call, onboarding_call, or onboarding_form.`);
}

// Sanitise and restrict paths
const transcriptPath = restrictPath(sanitizeArg(rawTranscriptPath, 'transcript_path'), 'transcript_path');
const model = sanitizeArg(rawModel, 'model');
// ollama_url is a URL — validate as URL rather than shell-arg
let ollamaUrl;
try {
  const u = new URL(rawOllamaUrl);
  if (!['http:', 'https:'].includes(u.protocol)) throw new Error('protocol');
  ollamaUrl = rawOllamaUrl;
} catch {
  throw new Error(`'ollama_url' is not a valid http/https URL: ${rawOllamaUrl}`);
}

const fs = require('fs');
if (!fs.existsSync(transcriptPath)) {
  throw new Error(`Transcript file not found: ${transcriptPath}`);
}

return [{
  json: {
    transcript_path: transcriptPath,
    stage,
    model,
    ollama_url: ollamaUrl,
    received_at: new Date().toISOString(),
    request_id: `req-${Date.now()}`
  }
}];

// Parse Script 1 output — prefers reading .pipeline_meta.json (R-2 fix)
// Falls back to stdout regex only if the meta file is absent (e.g. old install).
const stdout   = $input.first().json.stdout   || '';
const stderr   = $input.first().json.stderr   || '';
const exitCode = $input.first().json.exitCode;

if (exitCode !== 0) {
  throw new Error(`Script 1 failed (exit ${exitCode}):\n${stderr || stdout}`);
}

const fs = require('fs');
const prevJson = $input.first().json;

// ── R-2 fix: try reading the stable meta file first ───────────────────────────
// Script 1 writes outputs/accounts/{id}/{version}/.pipeline_meta.json
// We scan recently-modified subdirectories to locate it, or fall back to stdout.
let accountId, confidence, unknowns;

// Attempt to find the latest written meta file under outputs/accounts/
const accountsBase = '/app/clara_pipeline/outputs/accounts';
let metaData = null;
try {
  if (fs.existsSync(accountsBase)) {
    // Find the meta file whose mtime is closest to now
    let latestMtime = 0;
    const walkDirs = (dir, depth) => {
      if (depth > 3) return;
      for (const entry of fs.readdirSync(dir)) {
        const full = `${dir}/${entry}`;
        try {
          const stat = fs.statSync(full);
          if (stat.isDirectory()) {
            walkDirs(full, depth + 1);
          } else if (entry === '.pipeline_meta.json' && stat.mtimeMs > latestMtime) {
            latestMtime = stat.mtimeMs;
            metaData = JSON.parse(fs.readFileSync(full, 'utf8'));
          }
        } catch(e) { /* skip unreadable entries */ }
      }
    };
    walkDirs(accountsBase, 0);
  }
} catch(e) {
  console.log(`[WARN] Could not scan for meta file: ${e.message}`);
}

if (metaData && metaData.account_id) {
  accountId  = metaData.account_id;
  confidence = metaData.extraction_confidence || 'unknown';
  unknowns   = metaData.unknowns_count   || 0;
  console.log(`[INFO] Loaded account_id from .pipeline_meta.json: ${accountId}`);
} else {
  // ── Fallback: stdout regex (kept for backward compatibility) ─────────────
  const accountMatch = stdout.match(/Account ID:\s+(CLARA-\d{4}-\d{3})/);
  if (!accountMatch) {
    throw new Error(`Could not find account_id in Script 1 output. stdout: ${stdout.slice(0, 500)}`);
  }
  accountId  = accountMatch[1];
  const confMatch    = stdout.match(/Confidence:\s+(\w+)/);
  confidence         = confMatch ? confMatch[1] : 'unknown';
  const unknownsMatch = stdout.match(/Unknowns:\s+(\d+)/);
  unknowns           = unknownsMatch ? parseInt(unknownsMatch[1]) : 0;
  console.log(`[WARN] .pipeline_meta.json not found — fell back to stdout regex for account_id.`);
}

const memoPath = `/app/clara_pipeline/outputs/accounts/${accountId}/v1/account_memo.json`;

return [{
  json: {
    ...prevJson,
    account_id: accountId,
    memo_path: memoPath,
    extraction_confidence: confidence,
    unknowns_count: unknowns,
    script1_stdout: stdout,
    script1_status: 'ok'
  }
}];

// Parse Script 2 output and determine spec status
const stdout = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode;
const accountId = $input.first().json.account_id;

if (exitCode !== 0) {
  throw new Error(`Script 2 failed (exit ${exitCode}):\n${stdout}`);
}

// Determine if draft or go-live ready
const isDraft = stdout.includes('DRAFT') || stdout.includes('NOT READY FOR GO-LIVE');
const questionsMatch = stdout.match(/Questions:\s+(\d+)/);
const questions = questionsMatch ? parseInt(questionsMatch[1]) : 0;

const specFilename = isDraft ? 'retell_agent_spec.draft.json' : 'retell_agent_spec.json';
const specPath = `/app/clara_pipeline/outputs/accounts/${accountId}/v1/${specFilename}`;

const prevJson = $input.first().json;

return [{
  json: {
    ...prevJson,
    spec_path: specPath,
    spec_status: isDraft ? 'draft' : 'ready',
    questions_count: questions,
    script2_stdout: stdout,
    script2_status: 'ok',
    pipeline: 'A'
  }
}];

// Read the generated memo JSON for logging and task creation
const fs = require('fs');
const memoPath = $input.first().json.memo_path;
const specPath = $input.first().json.spec_path;

let memo = {};
let spec = {};

try {
  memo = JSON.parse(fs.readFileSync(memoPath, 'utf8'));
} catch(e) {
  console.log(`Warning: could not read memo at ${memoPath}: ${e.message}`);
}

try {
  spec = JSON.parse(fs.readFileSync(specPath, 'utf8'));
} catch(e) {
  console.log(`Warning: could not read spec at ${specPath}: ${e.message}`);
}

const prevJson = $input.first().json;

return [{
  json: {
    ...prevJson,
    company_name: memo.company?.name || '[Unknown]',
    business_hours_timezone: memo.business_hours?.timezone || null,
    unknowns: memo.questions_or_unknowns || [],
    go_live_ready: prevJson.spec_status === 'ready',
    agent_name: spec.agent_name || `Clara - ${memo.company?.name || 'Unknown'}`,
    memo_snapshot: {
      account_id: memo.account_id,
      version: memo.version,
      extraction_confidence: memo.extraction_confidence,
      questions_or_unknowns: memo.questions_or_unknowns?.length || 0
    }
  }
}];

// ── Task Tracker: Write tracking item to outputs/tasks.json ──────────────
// Fulfills PDF requirement: "A tracking item created in a task tool"
// Using local tasks.json as a zero-cost alternative to Asana/Trello.
// To upgrade to Asana: replace this node with n8n's native Asana node.
// To upgrade to Trello: replace with n8n's native Trello node.

const fs = require('fs');
const path = require('path');

const d = $input.first().json;
const tasksPath = '/app/clara_pipeline/outputs/tasks.json';

let tasks = [];
try {
  if (fs.existsSync(tasksPath)) {
    tasks = JSON.parse(fs.readFileSync(tasksPath, 'utf8'));
  }
} catch(e) {}

// Find existing task for this account (idempotent update)
const existing = tasks.findIndex(t => t.account_id === d.account_id);

const task = {
  task_id: `TASK-${d.account_id}`,
  account_id: d.account_id,
  company_name: d.company_name,
  agent_name: d.agent_name,
  status: d.go_live_ready ? 'ready_for_retell_import' : 'pending_onboarding',
  spec_status: d.spec_status,
  go_live_ready: d.go_live_ready,
  unknowns_count: d.unknowns_count,
  outputs: {
    memo: d.memo_path,
    spec: d.spec_path
  },
  next_action: d.go_live_ready
    ? 'Import retell_agent_spec.json into Retell UI (see README: Retell Manual Import Instructions)'
    : `Schedule onboarding call — ${d.unknowns_count} unknown(s) to resolve`,
  created_at: existing >= 0 ? tasks[existing].created_at : new Date().toISOString(),
  updated_at: new Date().toISOString(),
  pipeline_run: d.request_id
};

if (existing >= 0) {
  tasks[existing] = task;
} else {
  tasks.push(task);
}

fs.mkdirSync(path.dirname(tasksPath), { recursive: true });
fs.writeFileSync(tasksPath, JSON.stringify(tasks, null, 2));

console.log(`Task tracker updated: ${task.task_id} → ${task.status}`);

return [{ json: { ...d, task_id: task.task_id, task_status: task.status } }];

// Log run to outputs/pipeline_log.json
const fs = require('fs');
const path = require('path');

const logPath = '/app/clara_pipeline/outputs/pipeline_log.json';
let log = [];

try {
  if (fs.existsSync(logPath)) {
    log = JSON.parse(fs.readFileSync(logPath, 'utf8'));
  }
} catch(e) {}

const entry = {
  timestamp: new Date().toISOString(),
  pipeline: 'A',
  account_id: $input.first().json.account_id,
  company_name: $input.first().json.company_name,
  transcript: $input.first().json.transcript_path,
  stage: $input.first().json.stage,
  extraction_confidence: $input.first().json.extraction_confidence,
  spec_status: $input.first().json.spec_status,
  go_live_ready: $input.first().json.go_live_ready,
  unknowns_count: $input.first().json.unknowns_count,
  task_id: $input.first().json.task_id,
  outputs: {
    memo: $input.first().json.memo_path,
    spec: $input.first().json.spec_path
  }
};

log.push(entry);

fs.mkdirSync(path.dirname(logPath), { recursive: true });
fs.writeFileSync(logPath, JSON.stringify(log, null, 2));

return [{ json: { ...($input.first().json), log_entry: entry } }];

